/**
 * DungeonScene — Room-based dungeon interior exploration.
 *
 * PixiJS canvas renders the dungeon grid (rooms as rectangles, corridors as
 * thin lines, party marker as a gold diamond). All sidebar UI is HTML/CSS DOM.
 *
 * The scene receives { dungeonType, regionLevel, seed } from SceneManager and
 * uses DungeonSystem to generate (or restore) the dungeon layout.
 *
 * Fog states per room:
 *   unknown  — black rectangle
 *   visited  — dim version of room color
 *   current  — bright, highlighted
 *
 * @module DungeonScene
 */

import { Graphics, Container } from 'pixi.js';
import SceneManager from '../core/SceneManager.js';
import EventBus from '../core/EventBus.js';
import DebugLog from '../debug/DebugLog.js';
import WorldState from '../world/WorldState.js';
import DungeonSystem from '../systems/DungeonSystem.js';
import InputManager from '../input/InputManager.js';

// ─── Layout constants ─────────────────────────────────────────────────────────

const ROOM_W = 80;       // px per room cell (canvas)
const ROOM_H = 60;
const ROOM_GAP_X = 20;
const ROOM_GAP_Y = 16;
const GRID_OFFSET_X = 40;
const GRID_OFFSET_Y = 40;

const CORRIDOR_W = 4;

// Room-type colors (canvas rendering)
const ROOM_COLORS = {
  entrance:  0x3a6a2a, // earthy green
  corridor:  0x3a3030, // dim grey-brown
  chamber:   0x2a2840, // deep indigo
  treasure:  0x5a4a10, // gold-brown
  boss:      0x5a0a0a, // dark red
};

const ROOM_COLORS_VISITED = {
  entrance:  0x223818,
  corridor:  0x201c1c,
  chamber:   0x181624,
  treasure:  0x302408,
  boss:      0x300606,
};

const ROOM_BORDER_CURRENT = 0xffd700;
const ROOM_BORDER_VISITED = 0x5a4a2a;
const ROOM_BORDER_UNKNOWN = 0x222222;

// ─── Helpers ──────────────────────────────────────────────────────────────────

function roomPixelPos(room) {
  return {
    px: GRID_OFFSET_X + room.x * (ROOM_W + ROOM_GAP_X),
    py: GRID_OFFSET_Y + room.y * (ROOM_H + ROOM_GAP_Y),
  };
}

function roomCenter(room) {
  const { px, py } = roomPixelPos(room);
  return { cx: px + ROOM_W / 2, cy: py + ROOM_H / 2 };
}

// ─── DungeonScene ─────────────────────────────────────────────────────────────

export default class DungeonScene {

  async init({ renderer, dungeonType = 'burial_mound', regionLevel = 1, seed = null } = {}) {
    this._renderer = renderer;
    this._dungeonType = dungeonType;
    this._regionLevel = regionLevel;
    this._seed = (seed != null) ? seed : ((WorldState.world?.seed ?? Date.now()) ^ 0xD00600);

    // PixiJS containers
    this._dungeonContainer = null;
    this._partyGfx = null;

    // Ticker
    this._ticker = null;

    // Event unsubs
    this._resizeUnsub = null;

    // Input cooldown — prevent rapid room navigation
    this._inputCooldown = 0;

    // Confirm-prompt state
    this._confirmPrompt = null;

    // ── Init or restore dungeon state ────────────────────────────────────────
    const savedState = WorldState.dungeonState ?? null;

    if (savedState && savedState.seed === this._seed && savedState.dungeonType === this._dungeonType) {
      DungeonSystem.restoreState(savedState);
      DebugLog.info(`[dungeon] Restored existing dungeon state; seed=${this._seed}`);
    } else {
      const dungeon = DungeonSystem.generate(this._seed, this._dungeonType, this._regionLevel);
      if (!dungeon) {
        DebugLog.error('[dungeon] DungeonScene: generate() returned null; aborting');
        SceneManager.transition('localMap', { regionId: WorldState.currentRegionId ?? 0 });
        return;
      }
      DungeonSystem.restoreState(dungeon);
      WorldState.dungeonState = DungeonSystem.getState();
    }

    // Enter the current room (marks visited)
    const currentId = DungeonSystem.getState().currentRoomId;
    DungeonSystem.enterRoom(currentId);
    WorldState.dungeonState = DungeonSystem.getState();

    // ── Build visuals ────────────────────────────────────────────────────────
    this._buildPixiDungeon();
    this._buildHTMLPanel();

    // Ticker
    this._ticker = (ticker) => this._update(ticker.deltaMS);
    this._renderer.app.ticker.add(this._ticker);

    this._resizeUnsub = EventBus.on('renderer:resize', () => this._onResize());

    // ── Debug API ────────────────────────────────────────────────────────────
    window.__debug = window.__debug ?? {};
    window.__debug.currentScene = 'dungeon';
    window.__debug.getDungeonState = () => DungeonSystem.getState();
    window.__debug.dungeonGoToRoom = (id) => this._navigateToRoom(id);

    DebugLog.info(`[dungeon] DungeonScene initialized; type=${this._dungeonType} seed=${this._seed}`);
  }

  // ─── PixiJS rendering ────────────────────────────────────────────────────────

  _buildPixiDungeon() {
    const worldLayer = this._renderer.layers.world;

    this._dungeonContainer = new Container();
    this._dungeonContainer.label = 'dungeonContainer';
    worldLayer.addChild(this._dungeonContainer);

    this._redrawDungeon();
  }

  _redrawDungeon() {
    if (!this._dungeonContainer) return;

    this._dungeonContainer.removeChildren();

    const state = DungeonSystem.getState();
    if (!state) return;

    const gfx = new Graphics();
    this._dungeonContainer.addChild(gfx);

    const currentId = state.currentRoomId;

    // ── Draw connections (corridors) first ────────────────────────────────
    for (const conn of state.connections) {
      const roomA = state.rooms.find(r => r.id === conn.from);
      const roomB = state.rooms.find(r => r.id === conn.to);
      if (!roomA || !roomB) continue;

      const isVisible = roomA.visited || roomB.visited;
      if (!isVisible) continue;

      const { cx: ax, cy: ay } = roomCenter(roomA);
      const { cx: bx, cy: by } = roomCenter(roomB);

      gfx.moveTo(ax, ay);
      gfx.lineTo(bx, by);
      gfx.stroke({ color: 0x4a3a2a, width: CORRIDOR_W });
    }

    // ── Draw rooms ────────────────────────────────────────────────────────
    for (const room of state.rooms) {
      const { px, py } = roomPixelPos(room);
      const isCurrent = room.id === currentId;
      const isVisited = room.visited;

      // Unknown rooms are hidden
      if (!isVisited && !isCurrent) {
        gfx.rect(px, py, ROOM_W, ROOM_H);
        gfx.fill({ color: 0x111111 });
        gfx.rect(px, py, ROOM_W, ROOM_H);
        gfx.stroke({ color: ROOM_BORDER_UNKNOWN, width: 1 });
        continue;
      }

      const fillColor = isCurrent
        ? (ROOM_COLORS[room.type] ?? 0x2a2a3a)
        : (ROOM_COLORS_VISITED[room.type] ?? 0x181820);

      const borderColor = isCurrent
        ? ROOM_BORDER_CURRENT
        : ROOM_BORDER_VISITED;

      const borderWidth = isCurrent ? 2 : 1;

      gfx.rect(px, py, ROOM_W, ROOM_H);
      gfx.fill({ color: fillColor });
      gfx.rect(px, py, ROOM_W, ROOM_H);
      gfx.stroke({ color: borderColor, width: borderWidth });

      // Cleared indicator — small checkmark in top-right corner
      if (room.cleared) {
        gfx.circle(px + ROOM_W - 8, py + 8, 5);
        gfx.fill({ color: 0x20aa40 });
      }

      // Loot indicator — small gem in bottom-left corner
      if (!room.cleared && room.loot?.items?.length > 0) {
        gfx.circle(px + 8, py + ROOM_H - 8, 4);
        gfx.fill({ color: 0xddaa00 });
      }
    }

    // ── Draw party marker (gold diamond) ─────────────────────────────────
    const currentRoom = state.rooms.find(r => r.id === currentId);
    if (currentRoom) {
      const { cx, cy } = roomCenter(currentRoom);
      const d = 8; // half-diagonal
      gfx.poly([cx, cy - d, cx + d, cy, cx, cy + d, cx - d, cy]);
      gfx.fill({ color: 0xffd700 });
      gfx.poly([cx, cy - d, cx + d, cy, cx, cy + d, cx - d, cy]);
      gfx.stroke({ color: 0xffffff, width: 1.5 });
    }
  }

  // ─── HTML Panel ──────────────────────────────────────────────────────────────

  _buildHTMLPanel() {
    const existing = document.getElementById('panel-dungeon');
    if (existing) existing.remove();

    const panel = document.createElement('div');
    panel.id = 'panel-dungeon';
    panel.className = 'dungeon-panel';
    panel.style.cssText = `
      position: fixed;
      top: 0;
      right: 0;
      bottom: 0;
      width: clamp(220px, 22vw, 320px);
      background: rgba(8, 6, 4, 0.92);
      border-left: 1px solid #5a4a2a;
      padding: 16px;
      color: #ddccaa;
      font-family: Georgia, 'Times New Roman', serif;
      z-index: 150;
      overflow-y: auto;
      display: flex;
      flex-direction: column;
      gap: 12px;
      box-sizing: border-box;
    `;

    const def = DungeonSystem.getDef(this._dungeonType);

    panel.innerHTML = `
      <div id="dungeon-title" style="
        font-size: clamp(14px, 1.5vw, 18px);
        font-weight: bold;
        color: #c8a020;
        letter-spacing: 0.05em;
        text-transform: uppercase;
        border-bottom: 1px solid #3a2a0a;
        padding-bottom: 8px;
      ">${def?.name ?? 'Dungeon'}</div>

      <div id="dungeon-room-info" style="
        background: rgba(20, 15, 8, 0.8);
        border: 1px solid #3a2a0a;
        border-radius: 3px;
        padding: 10px;
        font-size: clamp(11px, 1.1vw, 13px);
        line-height: 1.6;
      ">Loading...</div>

      <div id="dungeon-enemies" style="
        font-size: clamp(11px, 1.1vw, 12px);
        color: #cc6655;
        min-height: 20px;
      "></div>

      <div id="dungeon-loot" style="
        font-size: clamp(11px, 1.1vw, 12px);
        color: #ddaa00;
        min-height: 20px;
      "></div>

      <div style="display: flex; flex-direction: column; gap: 6px;" id="dungeon-actions">
        <button id="btn-dungeon-explore" class="dungeon-btn" style="${this._btnStyle()}">Explore</button>
        <button id="btn-dungeon-fight"   class="dungeon-btn" style="${this._btnStyle('danger')}">Fight</button>
        <button id="btn-dungeon-loot"    class="dungeon-btn" style="${this._btnStyle('gold')}">Collect Loot</button>
        <button id="btn-dungeon-leave"   class="dungeon-btn" style="${this._btnStyle()}">Leave Dungeon</button>
      </div>

      <div id="dungeon-nav-rooms" style="
        font-size: clamp(10px, 1vw, 12px);
        color: #9a8a6a;
        border-top: 1px solid #2a1a0a;
        padding-top: 8px;
      "><strong style="color:#c8a020;">Connected rooms:</strong><div id="dungeon-nav-list" style="margin-top:4px;"></div></div>

      <div id="dungeon-status" style="
        font-size: clamp(9px, 0.9vw, 11px);
        color: #6a5a4a;
        text-align: center;
      "></div>
    `;

    document.body.appendChild(panel);
    this._panel = panel;

    // Wire up action buttons
    document.getElementById('btn-dungeon-explore')?.addEventListener('click', () => this._onExplore());
    document.getElementById('btn-dungeon-fight')?.addEventListener('click',   () => this._onFight());
    document.getElementById('btn-dungeon-loot')?.addEventListener('click',    () => this._onLoot());
    document.getElementById('btn-dungeon-leave')?.addEventListener('click',   () => this._onLeave());

    this._updatePanel();
  }

  _btnStyle(variant = 'default') {
    const base = `
      background: #1a1208;
      border: 1px solid #5a4a2a;
      color: #ddccaa;
      padding: 8px 10px;
      cursor: pointer;
      font-size: clamp(11px, 1.1vw, 13px);
      font-family: Georgia, serif;
      border-radius: 3px;
      text-align: left;
      width: 100%;
      transition: background 0.15s;
    `;
    if (variant === 'danger') return base + 'color: #ff8877; border-color: #7a2a2a;';
    if (variant === 'gold')   return base + 'color: #ddaa00; border-color: #7a5a00;';
    return base;
  }

  _updatePanel() {
    const state = DungeonSystem.getState();
    if (!state || !this._panel) return;

    const room = DungeonSystem.getCurrentRoom();
    if (!room) return;

    const def = DungeonSystem.getDef(this._dungeonType);

    // Room info
    const infoEl = document.getElementById('dungeon-room-info');
    if (infoEl) {
      const typeLabel = room.type.charAt(0).toUpperCase() + room.type.slice(1);
      const clearedLabel = room.cleared ? '<span style="color:#20aa40">Cleared</span>' : '';
      infoEl.innerHTML = `
        <div style="font-weight:bold; color:#e8d8a0; margin-bottom:4px;">${typeLabel} ${clearedLabel}</div>
        <div style="color:#9a8a6a; font-size:0.9em;">${def?.description ?? ''}</div>
      `;
    }

    // Enemies
    const enemyEl = document.getElementById('dungeon-enemies');
    if (enemyEl) {
      if (!room.cleared && room.encounter?.present) {
        const names = room.encounter.enemies.map(e =>
          e.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())
        ).join(', ');
        const bossTag = room.encounter.isBoss ? ' <span style="color:#ff5533">[BOSS]</span>' : '';
        enemyEl.innerHTML = `Enemies: ${names}${bossTag}`;
      } else {
        enemyEl.innerHTML = '';
      }
    }

    // Loot
    const lootEl = document.getElementById('dungeon-loot');
    if (lootEl) {
      if (room.cleared && room.loot?.items?.length > 0) {
        const itemNames = room.loot.items.map(i =>
          i.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())
        ).join(', ');
        lootEl.innerHTML = `Loot available: ${itemNames}` +
          (room.loot.gold > 0 ? ` + ${room.loot.gold} gold` : '');
      } else if (!room.cleared && room.loot?.items?.length > 0) {
        lootEl.innerHTML = `Loot here (clear room first)`;
      } else {
        lootEl.innerHTML = '';
      }
    }

    // Action button visibility
    const exploreBtn = document.getElementById('btn-dungeon-explore');
    const fightBtn   = document.getElementById('btn-dungeon-fight');
    const lootBtn    = document.getElementById('btn-dungeon-loot');
    const leaveBtn   = document.getElementById('btn-dungeon-leave');

    const hasEnemy = !room.cleared && room.encounter?.present;
    const hasLoot  = room.cleared && room.loot?.items?.length > 0;
    const atEntrance = room.type === 'entrance';

    if (exploreBtn) exploreBtn.style.display = (!hasEnemy && !room.cleared) ? 'block' : 'none';
    if (fightBtn)   fightBtn.style.display   = hasEnemy ? 'block' : 'none';
    if (lootBtn)    lootBtn.style.display     = hasLoot  ? 'block' : 'none';
    if (leaveBtn)   leaveBtn.style.display    = atEntrance ? 'block' : 'none';

    // Connected rooms nav
    const navList = document.getElementById('dungeon-nav-list');
    if (navList) {
      const connected = DungeonSystem.getConnectedRooms(room.id);
      if (connected.length === 0) {
        navList.innerHTML = '<span style="color:#4a3a2a">No exits</span>';
      } else {
        navList.innerHTML = connected.map(r => {
          const typeLabel = r.type.charAt(0).toUpperCase() + r.type.slice(1);
          const visitLabel = r.visited ? '' : ' <span style="color:#4a4a6a">[unknown]</span>';
          const clearedLabel = r.cleared ? ' <span style="color:#20aa40">✓</span>' : '';
          return `<div style="margin:2px 0;">
            <button onclick="window.__dungeonNav_${r.id}()" style="
              background: none; border: none; color: #aaa89a; cursor: pointer;
              font-family: Georgia, serif; font-size: 0.95em; text-align: left;
              padding: 2px 0; text-decoration: underline;
            ">${typeLabel}${visitLabel}${clearedLabel}</button>
          </div>`;
        }).join('');

        // Attach nav handlers to window so the inline onclick can find them
        for (const r of connected) {
          window[`__dungeonNav_${r.id}`] = () => this._navigateToRoom(r.id);
        }
      }
    }

    // Status line
    const statusEl = document.getElementById('dungeon-status');
    if (statusEl) {
      const total = state.rooms.length;
      const cleared = state.rooms.filter(r => r.cleared).length;
      statusEl.textContent = `${cleared}/${total} rooms cleared`;
    }
  }

  // ─── Action handlers ─────────────────────────────────────────────────────────

  _onExplore() {
    const room = DungeonSystem.getCurrentRoom();
    if (!room) return;

    if (room.cleared) {
      this._showStatus('Room already explored.');
      return;
    }

    // No encounter — just mark cleared
    DungeonSystem.clearRoom(room.id);
    WorldState.dungeonState = DungeonSystem.getState();

    DebugLog.event(`[dungeon] Explored room; id=${room.id} type=${room.type}`);
    this._showStatus('You explore the room carefully.');
    this._redrawDungeon();
    this._updatePanel();
  }

  _onFight() {
    const room = DungeonSystem.getCurrentRoom();
    if (!room || !room.encounter?.present) {
      this._showStatus('Nothing to fight here.');
      return;
    }

    DebugLog.event(`[dungeon] Fight triggered; room=${room.id} enemies=${room.encounter.enemies}`);

    // Build enemy list for CombatScene
    const enemies = room.encounter.enemies.map((enemyId, i) => ({
      id: `dungeon_enemy_${i}`,
      type: enemyId,
      name: enemyId.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase()),
      level: this._regionLevel + (room.encounter.isBoss ? 2 : 0),
    }));

    const partyChars = window.__partyChars ?? [];

    // Pass dungeon context so CombatScene can call back
    SceneManager.transition('combat', {
      partyChars,
      enemies,
      sourceEncounter: { type: 'combat', dungeonRoomId: room.id, isDungeon: true },
      onCombatEnd: (result) => this._onCombatResult(room.id, result),
    });
  }

  _onCombatResult(roomId, result) {
    if (result?.victory) {
      DungeonSystem.clearRoom(roomId);
      WorldState.dungeonState = DungeonSystem.getState();
      DebugLog.event(`[dungeon] Combat won; room=${roomId} cleared`);
    }
  }

  _onLoot() {
    const room = DungeonSystem.getCurrentRoom();
    if (!room || !room.cleared || !room.loot?.items?.length) {
      this._showStatus('Nothing to loot here.');
      return;
    }

    const loot = room.loot;
    DebugLog.event(`[dungeon] Looted room; id=${room.id} items=${JSON.stringify(loot.items)} gold=${loot.gold}`);

    // Add gold to party
    if (loot.gold > 0) {
      WorldState.partyGold = (WorldState.partyGold ?? 0) + loot.gold;
    }

    // Clear loot so it can't be taken again
    room.loot = null;
    WorldState.dungeonState = DungeonSystem.getState();

    const itemList = loot.items.map(i =>
      i.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())
    ).join(', ');

    this._showStatus(`Looted: ${itemList}` + (loot.gold > 0 ? ` + ${loot.gold} gold` : ''));
    this._redrawDungeon();
    this._updatePanel();
  }

  _onLeave() {
    if (!DungeonSystem.canExitDungeon()) {
      this._showStatus('Return to the entrance to leave the dungeon.');
      return;
    }

    DebugLog.event('[dungeon] Party leaving dungeon');

    // Clear dungeon state from WorldState
    WorldState.dungeonState = null;

    // If world data exists transition to local map; otherwise fall back to world map
    if (WorldState.world) {
      SceneManager.transition('localMap', { regionId: WorldState.currentRegionId ?? 0 });
    } else {
      SceneManager.transition('worldMap');
    }
  }

  _navigateToRoom(roomId) {
    const state = DungeonSystem.getState();
    if (!state) return;

    // Verify the room is connected to the current room
    const connected = DungeonSystem.getConnectedRooms(state.currentRoomId);
    const targetRoom = connected.find(r => r.id === roomId);

    if (!targetRoom) {
      this._showStatus('You cannot reach that room from here.');
      return;
    }

    const { room } = DungeonSystem.enterRoom(roomId);
    WorldState.dungeonState = DungeonSystem.getState();

    DebugLog.event(`[dungeon] Navigated to room; id=${roomId} type=${room?.type}`);

    this._redrawDungeon();
    this._updatePanel();
  }

  _showStatus(msg) {
    const el = document.getElementById('dungeon-status');
    if (el) {
      el.textContent = msg;
      el.style.color = '#c8a020';
      clearTimeout(this._statusTimer);
      this._statusTimer = setTimeout(() => {
        if (el) {
          const state = DungeonSystem.getState();
          const total = state?.rooms.length ?? 0;
          const cleared = state?.rooms.filter(r => r.cleared).length ?? 0;
          el.textContent = `${cleared}/${total} rooms cleared`;
          el.style.color = '#6a5a4a';
        }
      }, 3000);
    }
  }

  // ─── Input / game loop ────────────────────────────────────────────────────────

  _update(deltaMS) {
    if (this._inputCooldown > 0) {
      this._inputCooldown -= deltaMS;
    }
  }

  _onResize() {
    // Panel is fixed CSS — no PixiJS repositioning needed
    // Redraw dungeon to use any updated renderer dimensions
    this._redrawDungeon();
  }

  // ─── Lifecycle ───────────────────────────────────────────────────────────────

  _removeHTMLPanel() {
    if (this._panel) {
      this._panel.remove();
      this._panel = null;
    }

    // Clean up any nav callbacks we placed on window
    const state = DungeonSystem.getState();
    if (state) {
      for (const room of state.rooms) {
        delete window[`__dungeonNav_${room.id}`];
      }
    }
  }

  async destroy() {
    if (this._ticker && this._renderer?.app?.ticker) {
      this._renderer.app.ticker.remove(this._ticker);
      this._ticker = null;
    }

    if (this._dungeonContainer) {
      this._renderer.layers.world.removeChild(this._dungeonContainer);
      this._dungeonContainer.destroy({ children: true });
      this._dungeonContainer = null;
    }

    this._removeHTMLPanel();

    if (this._resizeUnsub) {
      this._resizeUnsub();
      this._resizeUnsub = null;
    }

    if (this._statusTimer) {
      clearTimeout(this._statusTimer);
      this._statusTimer = null;
    }

    // Clear dungeon debug hooks
    if (window.__debug) {
      delete window.__debug.getDungeonState;
      delete window.__debug.dungeonGoToRoom;
    }

    DebugLog.info('[dungeon] DungeonScene destroyed');
  }
}
