/**
 * DungeonSystem — Generates and manages dungeon layouts for Spellroads.
 *
 * Generates a grid of rooms (up to 5x5) connected by corridors.
 * Uses a seeded RNG so the same seed always produces the same dungeon.
 * State lives in WorldState.dungeonState; this system is stateless aside
 * from the currently active dungeon loaded via restoreState().
 *
 * Room types:
 *   'entrance'  — Entry/exit point; party starts and can leave here
 *   'corridor'  — Small connecting passage; may have minor loot
 *   'chamber'   — Standard room with possible encounter
 *   'treasure'  — No encounter; guaranteed loot
 *   'boss'      — Boss encounter; cleared only after defeating the boss
 *
 * @module DungeonSystem
 */

import { createRNG } from '../utils/RNG.js';
import DUNGEON_DEFS from '../data/dungeons.json';
import DebugLog from '../debug/DebugLog.js';

// ─── Constants ─────────────────────────────────────────────────────────────────

const GRID_W = 5;
const GRID_H = 5;

// Loot tables per tier
const LOOT_TABLES = {
  common:   ['iron_sword', 'leather_armor', 'health_potion', 'torch', 'rope'],
  uncommon: ['steel_sword', 'chain_armor', 'mana_potion', 'identify_scroll', 'rare_herb'],
  rare:     ['enchanted_blade', 'plate_armor', 'elixir_of_power', 'legendary_gem', 'ancient_tome'],
};

// ─── DungeonSystem ─────────────────────────────────────────────────────────────

const DungeonSystem = {
  /** @type {object|null} Currently active dungeon layout */
  _dungeon: null,

  // ── Public API ──────────────────────────────────────────────────────────────

  /**
   * Get the dungeon definition for a given type id.
   * @param {string} dungeonTypeId
   * @returns {object|null}
   */
  getDef(dungeonTypeId) {
    return DUNGEON_DEFS.find(d => d.id === dungeonTypeId) ?? null;
  },

  /**
   * Generate a dungeon layout from a seed.
   * Returns a full dungeon object that can be stored in WorldState.
   *
   * @param {number} seed — Deterministic seed
   * @param {string} dungeonTypeId — Key into dungeons.json
   * @param {number} regionLevel — Used to scale encounter difficulty
   * @returns {{
   *   seed: number,
   *   dungeonType: string,
   *   regionLevel: number,
   *   rooms: Array<object>,
   *   connections: Array<{from: string, to: string}>,
   *   startRoom: string,
   *   bossRoom: string,
   *   currentRoomId: string,
   * }}
   */
  generate(seed, dungeonTypeId, regionLevel) {
    const rng = createRNG(seed >>> 0);
    const def = this.getDef(dungeonTypeId);

    if (!def) {
      DebugLog.error(`[dungeon] Unknown dungeon type: ${dungeonTypeId}`);
      return null;
    }

    const [minRooms, maxRooms] = def.room_count;
    const targetRoomCount = rng.nextInt(minRooms, maxRooms);

    // ── Build room grid ───────────────────────────────────────────────────────
    // Start from a fixed entrance position, then spread rooms using BFS with RNG.

    const entranceX = 2; // center column
    const entranceY = GRID_H - 1; // bottom row

    const activeGrid = Array.from({ length: GRID_H }, () => Array(GRID_W).fill(null));
    const roomList = [];
    const connections = [];

    let roomIdCounter = 0;

    const makeRoom = (x, y, type) => {
      const id = `room_${roomIdCounter++}`;
      const encounter = this._makeEncounter(type, def, regionLevel, rng);
      const loot = this._makeLoot(type, def, rng);
      const room = { id, x, y, type, cleared: false, encounter, loot, visited: false };
      activeGrid[y][x] = room;
      roomList.push(room);
      return room;
    };

    // Place entrance
    const entranceRoom = makeRoom(entranceX, entranceY, 'entrance');

    // BFS frontier
    const frontier = [{ x: entranceX, y: entranceY }];
    const visited = new Set([`${entranceX},${entranceY}`]);

    const dirs = [
      { dx: 0, dy: -1 }, // north
      { dx: 1, dy: 0  }, // east
      { dx: 0, dy: 1  }, // south
      { dx: -1, dy: 0 }, // west
    ];

    let attempts = 0;
    while (roomList.length < targetRoomCount && frontier.length > 0 && attempts < 200) {
      attempts++;

      // Pick random frontier cell
      const idx = rng.nextInt(0, frontier.length - 1);
      const { x: fx, y: fy } = frontier[idx];

      // Shuffle directions
      const shuffledDirs = rng.shuffle([...dirs]);
      let placed = false;

      for (const { dx, dy } of shuffledDirs) {
        const nx = fx + dx;
        const ny = fy + dy;
        const key = `${nx},${ny}`;

        if (nx < 0 || nx >= GRID_W || ny < 0 || ny >= GRID_H) continue;
        if (visited.has(key)) continue;

        visited.add(key);

        // Choose room type
        let type = 'chamber';
        const roll = rng.nextFloat();
        if (roll < 0.15) type = 'corridor';
        else if (roll < 0.25) type = 'treasure';

        const newRoom = makeRoom(nx, ny, type);

        // Connect to parent
        const parentRoom = activeGrid[fy][fx];
        if (parentRoom) {
          connections.push({ from: parentRoom.id, to: newRoom.id });
        }

        frontier.push({ x: nx, y: ny });
        placed = true;

        if (roomList.length >= targetRoomCount) break;
      }

      if (!placed) {
        frontier.splice(idx, 1);
      }
    }

    // ── Place boss room ───────────────────────────────────────────────────────
    // Find a dead-end room farthest from entrance, convert to boss.
    const deadEnds = roomList.filter(r => {
      if (r.type === 'entrance') return false;
      const neighborCount = connections.filter(c => c.from === r.id || c.to === r.id).length;
      return neighborCount === 1;
    });

    // Prefer rooms farthest from entrance by Manhattan distance
    const sorted = [...deadEnds].sort((a, b) => {
      const da = Math.abs(a.x - entranceX) + Math.abs(a.y - entranceY);
      const db = Math.abs(b.x - entranceX) + Math.abs(b.y - entranceY);
      return db - da;
    });

    let bossRoom = sorted[0] ?? roomList.find(r => r.type !== 'entrance');

    if (bossRoom) {
      bossRoom.type = 'boss';
      bossRoom.encounter = {
        present: true,
        enemies: [def.boss],
        difficulty: regionLevel + 2,
        isBoss: true,
      };
      bossRoom.loot = this._makeLoot('boss', def, rng);
      bossRoom.cleared = false;
    }

    const dungeon = {
      seed,
      dungeonType: dungeonTypeId,
      regionLevel,
      rooms: roomList,
      connections,
      startRoom: entranceRoom.id,
      bossRoom: bossRoom?.id ?? entranceRoom.id,
      currentRoomId: entranceRoom.id,
    };

    DebugLog.info(`[dungeon] Generated ${dungeonTypeId}; seed=${seed} rooms=${roomList.length} boss=${bossRoom?.id}`);
    return dungeon;
  },

  /**
   * Load a dungeon object as the active dungeon.
   * @param {object} dungeon — Previously generated dungeon
   */
  restoreState(dungeon) {
    this._dungeon = dungeon;
    DebugLog.info(`[dungeon] State restored; currentRoom=${dungeon?.currentRoomId}`);
  },

  /**
   * Get the current active dungeon state (serializable for SaveSystem).
   * @returns {object|null}
   */
  getState() {
    return this._dungeon ? { ...this._dungeon } : null;
  },

  /**
   * Move the party into a room, marking it as visited.
   * Triggers encounter logic if encounter is present and room is uncleared.
   * @param {string} roomId
   * @returns {{ room: object, encounter: object|null }}
   */
  enterRoom(roomId) {
    if (!this._dungeon) return { room: null, encounter: null };

    const room = this._dungeon.rooms.find(r => r.id === roomId);
    if (!room) {
      DebugLog.warn(`[dungeon] enterRoom: unknown roomId=${roomId}`);
      return { room: null, encounter: null };
    }

    this._dungeon.currentRoomId = roomId;
    room.visited = true;

    const encounter = (!room.cleared && room.encounter?.present) ? room.encounter : null;

    DebugLog.event(`[dungeon] Entered room; id=${roomId} type=${room.type} cleared=${room.cleared} encounter=${!!encounter}`);
    return { room, encounter };
  },

  /**
   * Mark a room as cleared and make its loot available.
   * @param {string} roomId
   * @returns {object|null} Loot object for the cleared room
   */
  clearRoom(roomId) {
    if (!this._dungeon) return null;

    const room = this._dungeon.rooms.find(r => r.id === roomId);
    if (!room) return null;

    room.cleared = true;

    DebugLog.event(`[dungeon] Room cleared; id=${roomId} type=${room.type} loot=${JSON.stringify(room.loot)}`);
    return room.loot ?? null;
  },

  /**
   * Returns true when the party is in the entrance room and can leave.
   * @returns {boolean}
   */
  canExitDungeon() {
    if (!this._dungeon) return true;
    return this._dungeon.currentRoomId === this._dungeon.startRoom;
  },

  /**
   * Get the room object the party is currently in.
   * @returns {object|null}
   */
  getCurrentRoom() {
    if (!this._dungeon) return null;
    return this._dungeon.rooms.find(r => r.id === this._dungeon.currentRoomId) ?? null;
  },

  /**
   * Get all rooms connected to the given room.
   * @param {string} roomId
   * @returns {object[]}
   */
  getConnectedRooms(roomId) {
    if (!this._dungeon) return [];

    const connectedIds = this._dungeon.connections
      .filter(c => c.from === roomId || c.to === roomId)
      .map(c => (c.from === roomId ? c.to : c.from));

    return this._dungeon.rooms.filter(r => connectedIds.includes(r.id));
  },

  /**
   * Check whether all non-entrance rooms are cleared.
   * @returns {boolean}
   */
  isFullyCleared() {
    if (!this._dungeon) return false;
    return this._dungeon.rooms
      .filter(r => r.type !== 'entrance')
      .every(r => r.cleared);
  },

  // ── Internal helpers ────────────────────────────────────────────────────────

  /**
   * Build an encounter descriptor for a room.
   * @param {string} roomType
   * @param {object} def — Dungeon definition
   * @param {number} regionLevel
   * @param {object} rng
   * @returns {object}
   */
  _makeEncounter(roomType, def, regionLevel, rng) {
    if (roomType === 'entrance' || roomType === 'treasure') {
      return { present: false };
    }

    if (roomType === 'boss') {
      return {
        present: true,
        enemies: [def.boss],
        difficulty: regionLevel + 2,
        isBoss: true,
      };
    }

    // corridor: 30% chance; chamber: 65% chance
    const chance = roomType === 'corridor' ? 0.3 : 0.65;
    if (!rng.nextBool(chance)) {
      return { present: false };
    }

    // Pick 1–2 enemies from the pool (excluding the boss)
    const pool = def.enemy_pool.filter(e => e !== def.boss);
    const count = rng.nextInt(1, 2);
    const enemies = Array.from({ length: count }, () => rng.pick(pool));

    return {
      present: true,
      enemies,
      difficulty: regionLevel,
      isBoss: false,
    };
  },

  /**
   * Build a loot descriptor for a room.
   * @param {string} roomType
   * @param {object} def — Dungeon definition
   * @param {object} rng
   * @returns {object|null}
   */
  _makeLoot(roomType, def, rng) {
    const tier = def.loot_tier ?? 'common';
    const table = LOOT_TABLES[tier] ?? LOOT_TABLES.common;

    if (roomType === 'boss') {
      // Boss always drops 2–3 items
      const count = rng.nextInt(2, 3);
      const items = Array.from({ length: count }, () => rng.pick(table));
      return { items, gold: rng.nextInt(20, 60) * (def.loot_tier === 'rare' ? 3 : 1) };
    }

    if (roomType === 'treasure') {
      const items = [rng.pick(table), rng.pick(table)];
      return { items, gold: rng.nextInt(10, 40) };
    }

    if (roomType === 'chamber' && rng.nextBool(0.5)) {
      return { items: [rng.pick(table)], gold: rng.nextInt(0, 15) };
    }

    if (roomType === 'corridor' && rng.nextBool(0.25)) {
      return { items: [rng.pick(table)], gold: 0 };
    }

    return null;
  },
};

export default DungeonSystem;
